public class SeataWebClientFilter implements ExchangeFilterFunction {

	@Override
	public Mono<ClientResponse> filter(ClientRequest request, ExchangeFunction next) {
		String xid = RootContext.getXID();
		if (!StringUtils.hasLength(xid)) {
			return next.exchange(request);
		}
		ClientRequest newReq = ClientRequest.from(request)
				.headers(h -> h.add(RootContext.KEY_XID, xid))
				.build();
		return next.exchange(newReq);
	}


}

public class PublishLocalPlugin implements Plugin<Project> {
	@Override
	public void apply(Project project) {
		project.getPlugins().withType(MavenPublishPlugin.class).all(mavenPublish -> {
			PublishingExtension publishing = project.getExtensions().getByType(PublishingExtension.class);
			publishing.getRepositories().maven(maven -> {
				maven.setName("local");
				maven.setUrl(new File(project.getRootProject().getBuildDir(), "publications/repos"));
			});
		});
	}
}

public static String getExistsQueryString(String entityName, String countQueryPlaceHolder,
			Iterable<String> idAttributes) {

		String whereClause = Streamable.of(idAttributes).stream() //
				.map(idAttribute -> String.format(EQUALS_CONDITION_STRING, "x", idAttribute, idAttribute)) //
				.collect(Collectors.joining(" AND ", " WHERE ", ""));

		return String.format(COUNT_QUERY_STRING, countQueryPlaceHolder, entityName) + whereClause;
	}

public static boolean hasNamedParameter(Query query) {

	Assert.notNull(query, "Query must not be null");

	for (Parameter<?> parameter : query.getParameters()) {

		String name = parameter.getName();

		// Hibernate 3 specific hack as it returns the index as String for the name.
		if (name != null && NO_DIGITS.matcher(name).find()) {
			return true;
		}
	}

	return false;
}

void failed(@Nullable ConfigurableApplicationContext context, Throwable exception) {
	doWithListeners("spring.boot.application.failed",
			(listener) -> callFailedListener(listener, context, exception), (step) -> {
				step.tag("exception", exception.getClass().toString());
				String message = exception.getMessage();
				if (message != null) {
					step.tag("message", message);
				}
			});
}

private <S, U extends T> Root<U> applySpecificationToCriteria(Specification<U> spec, Class<U> domainClass,
			CriteriaQuery<S> query) {

		Root<U> root = query.from(domainClass);

		CriteriaBuilder builder = entityManager.getCriteriaBuilder();
		Predicate predicate = spec.toPredicate(root, query, builder);

		if (predicate != null) {
			query.where(predicate);
		}

		return root;
	}

public class OAS31ModelConverter implements ModelConverter {

	@Override
	public Schema<?> resolve(AnnotatedType type, ModelConverterContext context, Iterator<ModelConverter> chain) {
		if (chain.hasNext()) {
			Schema<?> resolvedSchema = chain.next().resolve(type, context, chain);
			if (resolvedSchema != null && !isComposedSchema(resolvedSchema)) {
				handleSchemaTypes(resolvedSchema);
			}
			return resolvedSchema;
		}
		return null;
	}

}

