static <T> Specification<T> composed(@Nullable Specification<T> lhs, @Nullable Specification<T> rhs,
			Combiner combiner) {

		return (root, query, builder) -> {

			Predicate thisPredicate = toPredicate(lhs, root, query, builder);
			Predicate otherPredicate = toPredicate(rhs, root, query, builder);

			if (thisPredicate == null) {
				return otherPredicate;
			}

			return otherPredicate == null ? thisPredicate : combiner.combine(builder, thisPredicate, otherPredicate);
		};
	}

@Aspect
public class StepScopeManager {

	@Around("execution(void org.springframework.batch.core.step.Step+.execute(*)) && target(step) && args(stepExecution)")
	public void execute(Step step, StepExecution stepExecution) throws JobInterruptedException {
		StepSynchronizationManager.register(stepExecution);
		try {
			step.execute(stepExecution);
		}
		finally {
			StepSynchronizationManager.release();
		}
	}

}

@Deprecated(since = "6.0", forRemoval = true)
abstract class BatchListenerFactoryHelper {

	public static <T> List<T> getListeners(StepListener[] listeners, Class<? super T> cls) {
		List<T> list = new ArrayList<>();
		for (StepListener stepListener : listeners) {
			if (cls.isAssignableFrom(stepListener.getClass())) {
				@SuppressWarnings("unchecked")
				T listener = (T) stepListener;
				list.add(listener);
			}
		}
		return list;
	}

}

